module reg_file_32bit
(
    input clk,
    input rst_n,
    input we,
    input [2:0] w_addr,
    input [31:0] w_data,
    input [2:0] r_addr_a,
    input [2:0] r_addr_b,
    output reg [31:0] r_data_a,
    output reg [31:0] r_data_b
);

reg [31:0] mem [0:7];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mem[0] <= 32'b0;
        mem[1] <= 32'b0;
        mem[2] <= 32'b0;
        mem[3] <= 32'b0;
        mem[4] <= 32'b0;
        mem[5] <= 32'b0;
        mem[6] <= 32'b0;
        mem[7] <= 32'b0;
    end
    else if (we) begin
        mem[w_addr] <= w_data;
    end
end

always @(*) begin
    r_data_a = mem[r_addr_a];
    r_data_b = mem[r_addr_b];
end

endmodule
